Section: Button / Description
Table data:
{
  "page": 29,
  "table_index": 4,
  "headers": [
    "Button",
    "Description"
  ],
  "rows": [
    {
      "Button": "(Play/pause)",
      "Description": "When pressed, the playback controls appear. Using these controls, you can control the media content that is playing. To use Game Bar, press and hold the button in Game Mode . Game Bar may not be supported depending on the model or geographical area."
    },
    {
      "Button": "(Volume)",
      "Description": "Move the button up or down to adjust the volume. To mute the sound, press the button. When pressed for 2 seconds or more, the Accessibility Shortcuts appears. may not be present, depending on the model."
    },
    {
      "Button": "(Channel)",
      "Description": "Move the button up or down to change the channel. To see the Guide screen, press the button. When pressed for 1 second or more, the Channel List screen appears. Press and hold the button up or down to quickly change the channel."
    },
    {
      "Button": "Launch app button",
      "Description": "Launch the app indicated by the button. Available apps may differ depending on the geographical area or contents provider. This function may not be supported depending on the model."
    }
  ],
  "source": "docling"
}

Section: Function / Description
Table data:
{
  "page": 98,
  "table_index": 10,
  "headers": [
    "Function",
    "Description"
  ],
  "rows": [
    {
      "Function": "Slideshow Speed",
      "Description": "Sets the slideshow speed. If there is only one image file in the USB device, the slide show is not played."
    },
    {
      "Function": "Slideshow Effect",
      "Description": "Applies transition effects to the slide show. If there is only one image file in the USB device, the slide show is not played."
    },
    {
      "Function": "Background Music",
      "Description": "Plays background music as you set in the pop-up window while the TV displays photos. The music files must be saved in the same USB device as the photo files. To pause the background music, select Background Music on the playback screen bottom."
    },
    {
      "Function": "Subtitles",
      "Description": "You can set the detailed subtitle options, such as the language, sync, size, and color. If subtitles are not displayed correctly, check the encoding setting."
    },
    {
      "Function": "Rotate",
      "Description": "Rotates the video."
    },
    {
      "Function": "Audio Language",
      "Description": "Changes the audio language. This function is only available if the video supports multi-track sound."
    },
    {
      "Function": "Information",
      "Description": "Displays detailed information about the current multimedia content."
    }
  ],
  "source": "docling"
}

